21	
22	YOSYS_NAMESPACE_BEGIN
23	
24	const int lut_input_plane_limit = 12;
25	
26	static bool read_next_line(char *&buffer, size_t &buffer_size, int &line_count, std::istream &f)
27	{
28		string strbuf;
29		int buffer_len = 0;
30		buffer[0] = 0;
31	
32		while (1)
33		{
34			buffer_len += strlen(buffer + buffer_len);
35			while (buffer_len > 0 && (buffer[buffer_len-1] == ' ' || buffer[buffer_len-1] == '\t' ||
36					buffer[buffer_len-1] == '\r' || buffer[buffer_len-1] == '\n'))
37				buffer[--buffer_len] = 0;
38	
39			if (buffer_size-buffer_len < 4096) {
40				buffer_size *= 2;
41				buffer = (char*)realloc(buffer, buffer_size);
42			}
43	
44			if (buffer_len == 0 || buffer[buffer_len-1] == '\\') {
45				if (buffer_len > 0 && buffer[buffer_len-1] == '\\')
46					buffer[--buffer_len] = 0;
47				line_count++;
48				if (!std::getline(f, strbuf))
49					return false;
50				while (buffer_size-buffer_len < strbuf.size()+1) {
51					buffer_size *= 2;
52					buffer = (char*)realloc(buffer, buffer_size);
53				}
54				strcpy(buffer+buffer_len, strbuf.c_str());
55			} else
56				return true;
57		}
58	}
59	
60	static std::pair<RTLIL::IdString, int> wideports_split(std::string name)
61	{
62		int pos = -1;
63	
64		if (name.empty() || name.back() != ']')
65			goto failed;
66	
67		for (int i = 0; i+1 < GetSize(name); i++) {
68			if (name[i] == '[')
69				pos = i;
70			else if (name[i] != '-' && (name[i] < '0' || name[i] > '9'))
71				pos = -1;
72			else if (name[i] == '-' && ((i != pos+1) || name[i+1] == ']'))
73				pos = -1;
74			else if (i == pos+2 && name[i] == '0' && name[i-1] == '-')
75				pos = -1;
76			else if (i == pos+1 && name[i] == '0' && name[i+1] != ']')
77				pos = -1;
78		}
79	
80		if (pos >= 0)
81			return std::pair<RTLIL::IdString, int>("\\" + name.substr(0, pos), atoi(name.c_str() + pos+1));
82	
83	failed:
84		return std::pair<RTLIL::IdString, int>(RTLIL::IdString(), 0);
85	}
86	
87	void parse_blif(RTLIL::Design *design, std::istream &f, IdString dff_name, bool run_clean, bool sop_mode, bool wideports)
88	{
89		RTLIL::Module *module = nullptr;
90		RTLIL::Const *lutptr = NULL;
91		RTLIL::Cell *sopcell = NULL;
92		RTLIL::Cell *lastcell = nullptr;
93		RTLIL::State lut_default_state = RTLIL::State::Sx;
94		std::string err_reason;
95		int blif_maxnum = 0, sopmode = -1;
96	
97		auto blif_wire = [&](const std::string &wire_name) -> Wire*
98		{
99			if (wire_name[0] == '$')
100			{
101				for (int i = 0; i+1 < GetSize(wire_name); i++)
102				{
103					if (wire_name[i] != '$')
104						continue;
105	
106					int len = 0;
107					while (i+len+1 < GetSize(wire_name) && '0' <= wire_name[i+len+1] && wire_name[i+len+1] <= '9')
108						len++;
109	
110					if (len > 0) {
111						string num_str = wire_name.substr(i+1, len);
112						int num = atoi(num_str.c_str()) & 0x0fffffff;
113						blif_maxnum = std::max(blif_maxnum, num);
114					}
115				}
116			}
117	
118			IdString wire_id = RTLIL::escape_id(wire_name);
119			Wire *wire = module->wire(wire_id);
120	
121			if (wire == nullptr)
122				wire = module->addWire(wire_id);
123	
124			return wire;
125		};
126	
127		dict<RTLIL::IdString, RTLIL::Const> *obj_attributes = nullptr;
128		dict<RTLIL::IdString, RTLIL::Const> *obj_parameters = nullptr;
129	
130		dict<RTLIL::IdString, std::pair<int, bool>> wideports_cache;
131	
132		size_t buffer_size = 4096;
133		char *buffer = (char*)malloc(buffer_size);
134		int line_count = 0;
135	
136		while (1)
137		{
138			if (!read_next_line(buffer, buffer_size, line_count, f)) {
139				if (module != nullptr)
140					goto error;
141				free(buffer);
142				return;
143			}
144	
145		continue_without_read:
146			if (buffer[0] == '#')
147				continue;
148	
149			if (buffer[0] == '.')
150			{
151				if (lutptr) {
152					for (auto bit : *lutptr)
153						if (bit == RTLIL::State::Sx)
154							bit = lut_default_state;
155					lutptr = NULL;
156					lut_default_state = RTLIL::State::Sx;
157				}
158	
159				if (sopcell) {
160					sopcell = NULL;
161					sopmode = -1;
162				}
163	
164				char *cmd = strtok(buffer, " \t\r\n");
165	
166				if (!strcmp(cmd, ".model")) {
167					if (module != nullptr)
168						goto error;
169					module = new RTLIL::Module;
170					lastcell = nullptr;
171					char *name = strtok(NULL, " \t\r\n");
172					if (name == nullptr)
173						goto error;
174					module->name = RTLIL::escape_id(name);
175					obj_attributes = &module->attributes;
176					obj_parameters = nullptr;
177					if (design->module(module->name))
178						log_error("Duplicate definition of module %s in line %d!\n", module->name.unescape(), line_count);
179					design->add(module);
180					continue;
181				}
182	
183				if (module == nullptr)
184					goto error;
185	
186				if (!strcmp(cmd, ".blackbox"))
187				{
188					module->attributes[ID::blackbox] = RTLIL::Const(1);
189					continue;
190				}
191	
192				if (!strcmp(cmd, ".end"))
193				{
194					for (auto &wp : wideports_cache)
195					{
196						auto name = wp.first;
197						int width = wp.second.first;
198						bool isinput = wp.second.second;
199	
200						RTLIL::Wire *wire = module->addWire(name, width);
201						wire->port_input = isinput;
202						wire->port_output = !isinput;
203	
204						for (int i = 0; i < width; i++) {
205							RTLIL::IdString other_name = name.str() + stringf("[%d]", i);
206							RTLIL::Wire *other_wire = module->wire(other_name);
207							if (other_wire) {
208								other_wire->port_input = false;
209								other_wire->port_output = false;
210								if (isinput)
211									module->connect(other_wire, SigSpec(wire, i));
212								else
213									module->connect(SigSpec(wire, i), other_wire);
214							}
215						}
216					}
217	
218					module->fixup_ports();
219					wideports_cache.clear();
220	
221					if (run_clean)
222					{
223						Const buffer_lut(vector<RTLIL::State>({State::S0, State::S1}));
224						vector<Cell*> remove_cells;
225	
226						for (auto cell : module->cells())
227							if (cell->type == ID($lut) && cell->getParam(ID::LUT) == buffer_lut) {
228								module->connect(cell->getPort(ID::Y), cell->getPort(ID::A));
229								remove_cells.push_back(cell);
230							}
231	
232						for (auto cell : remove_cells)
233							module->remove(cell);
234	
235						Wire *true_wire = module->wire(ID($true));
236						Wire *false_wire = module->wire(ID($false));
237						Wire *undef_wire = module->wire(ID($undef));
238	
239						if (true_wire != nullptr)
240							module->rename(true_wire, stringf("$true$%d", ++blif_maxnum));
241	
242						if (false_wire != nullptr)
243							module->rename(false_wire, stringf("$false$%d", ++blif_maxnum));
244	
245						if (undef_wire != nullptr)
246							module->rename(undef_wire, stringf("$undef$%d", ++blif_maxnum));
247	
248						autoidx.ensure_at_least(blif_maxnum+1);
249						blif_maxnum = 0;
250					}
251	
252					module = nullptr;
253					lastcell = nullptr;
254					obj_attributes = nullptr;
255					obj_parameters = nullptr;
256					continue;
257				}
258	
259				if (!strcmp(cmd, ".area") || !strcmp(cmd, ".delay") || !strcmp(cmd, ".wire_load_slope") || !strcmp(cmd, ".wire") ||
260				    !strcmp(cmd, ".input_arrival") || !strcmp(cmd, ".default_input_arrival") || !strcmp(cmd, ".output_required") ||
261				    !strcmp(cmd, ".default_output_required") || !strcmp(cmd, ".input_drive") || !strcmp(cmd, ".default_input_drive") ||
262				    !strcmp(cmd, ".max_input_load") || !strcmp(cmd, ".default_max_input_load") || !strcmp(cmd, ".output_load") ||
263				    !strcmp(cmd, ".default_output_load"))
264				{
265					log_warning("Blif delay constraints (%s) are not supported.", cmd);
266					continue;
267				}
268	
269				if (!strcmp(cmd, ".inputs") || !strcmp(cmd, ".outputs"))
270				{
271					char *p;
272					while ((p = strtok(NULL, " \t\r\n")) != NULL)
273					{
274						RTLIL::IdString wire_name(stringf("\\%s", p));
275						RTLIL::Wire *wire = module->wire(wire_name);
276						if (wire == nullptr)
277							wire = module->addWire(wire_name);
278						if (!strcmp(cmd, ".inputs"))
279							wire->port_input = true;
280						else
281							wire->port_output = true;
282	
283						if (wideports) {
284							std::pair<RTLIL::IdString, int> wp = wideports_split(p);
285							if (!wp.first.empty() && wp.second >= 0) {
286								wideports_cache[wp.first].first = std::max(wideports_cache[wp.first].first, wp.second + 1);
287								wideports_cache[wp.first].second = !strcmp(cmd, ".inputs");
288							}
289						}
290					}
291					obj_attributes = nullptr;
292					obj_parameters = nullptr;
293					continue;
294				}
295	
296				if (!strcmp(cmd, ".cname"))
297				{
298					char *p = strtok(NULL, " \t\r\n");
299					if (p == NULL)
300						goto error;
301	
302					if(lastcell == nullptr || module == nullptr)
303					{
304						err_reason = stringf("No primitive object to attach .cname %s.", p);
305						goto error_with_reason;
306					}
307	
308					module->rename(lastcell, RTLIL::escape_id(p));
309					continue;
310				}
311	
312				if (!strcmp(cmd, ".attr") || !strcmp(cmd, ".param")) {
313					char *n = strtok(NULL, " \t\r\n");
314					char *v = strtok(NULL, "\r\n");
315					IdString id_n = RTLIL::escape_id(n);
316					Const const_v;
317					if (v[0] == '"') {
318						std::string str(v+1);
319						if (str.back() == '"')
320							str.resize(str.size()-1);
321						const_v = Const(str);
322					} else {
323						int n = strlen(v);
324						Const::Builder const_v_builder(n);
325						for (int i = 0; i < n; i++)
326							const_v_builder.push_back(v[n-i-1] != '0' ? State::S1 : State::S0);
327						const_v = const_v_builder.build();
328					}
329					if (!strcmp(cmd, ".attr")) {
330						if (obj_attributes == nullptr) {
331							err_reason = stringf("No object to attach .attr too.");
332							goto error_with_reason;
333						}
334						(*obj_attributes)[id_n] = const_v;
335					} else {
336						if (obj_parameters == nullptr) {
337							err_reason = stringf("No object to attach .param too.");
338							goto error_with_reason;
339						}
340						(*obj_parameters)[id_n] = const_v;
341					}
342					continue;
343				}
344	
345				if (!strcmp(cmd, ".latch"))
346				{
347					char *d = strtok(NULL, " \t\r\n");
348					char *q = strtok(NULL, " \t\r\n");
349					char *edge = strtok(NULL, " \t\r\n");
350					char *clock = strtok(NULL, " \t\r\n");
351					char *init = strtok(NULL, " \t\r\n");
352					RTLIL::Cell *cell = nullptr;
353	
354					if (clock == nullptr && edge != nullptr) {
355						init = edge;
356						edge = nullptr;
357					}
358	
359					if (init != nullptr && (init[0] == '0' || init[0] == '1'))
360						blif_wire(q)->attributes[ID::init] = Const(init[0] == '1' ? 1 : 0, 1);
361	
362					if (clock == nullptr)
363						goto no_latch_clock;
364	
365					if (!strcmp(edge, "re"))
366						cell = module->addDffGate(NEW_ID, blif_wire(clock), blif_wire(d), blif_wire(q));
367					else if (!strcmp(edge, "fe"))
368						cell = module->addDffGate(NEW_ID, blif_wire(clock), blif_wire(d), blif_wire(q), false);
369					else if (!strcmp(edge, "ah"))
370						cell = module->addDlatchGate(NEW_ID, blif_wire(clock), blif_wire(d), blif_wire(q));
371					else if (!strcmp(edge, "al"))
372						cell = module->addDlatchGate(NEW_ID, blif_wire(clock), blif_wire(d), blif_wire(q), false);
373					else {
374				no_latch_clock:
375						if (dff_name.empty()) {
376							cell = module->addFfGate(NEW_ID, blif_wire(d), blif_wire(q));
377						} else {
378							cell = module->addCell(NEW_ID, dff_name);
379							cell->setPort(ID::D, blif_wire(d));
380							cell->setPort(ID::Q, blif_wire(q));
381						}
382					}
383	
384					lastcell = cell;
385					obj_attributes = &cell->attributes;
386					obj_parameters = &cell->parameters;
387					continue;
388				}
389	
390				if (!strcmp(cmd, ".gate") || !strcmp(cmd, ".subckt"))
391				{
392					char *p = strtok(NULL, " \t\r\n");
393					if (p == NULL)
394						goto error;
395	
396					IdString celltype = RTLIL::escape_id(p);
397					RTLIL::Cell *cell = module->addCell(NEW_ID, celltype);
398					RTLIL::Module *cell_mod = design->module(celltype);
399	
400					dict<RTLIL::IdString, dict<int, SigBit>> cell_wideports_cache;
401	
402					while ((p = strtok(NULL, " \t\r\n")) != NULL)
403					{
404						char *q = strchr(p, '=');
405						if (q == NULL || !q[0])
406							goto error;
407						*(q++) = 0;
408	
409						if (wideports) {
410							std::pair<RTLIL::IdString, int> wp = wideports_split(p);
411							if (wp.first.empty())
412								cell->setPort(RTLIL::escape_id(p), *q ? blif_wire(q) : SigSpec());
413							else
414								cell_wideports_cache[wp.first][wp.second] = blif_wire(q);
415						} else {
416							cell->setPort(RTLIL::escape_id(p), *q ? blif_wire(q) : SigSpec());
417						}
418					}
419	
420					for (auto &it : cell_wideports_cache)
421					{
422						int width = 0;
423						int offset = 0;
424						bool upto = false;
425						for (auto &b : it.second)
426							width = std::max(width, b.first + 1);
427	
428						if (cell_mod) {
429							Wire *cell_port = cell_mod->wire(it.first);
430							if (cell_port && (cell_port->port_input || cell_port->port_output)) {
431								offset = cell_port->start_offset;
432								upto = cell_port->upto;
433								width = cell_port->width;
434							}
435						}
436	
437						SigSpec sig;
438	
439						for (int i = 0; i < width; i++) {
440							int idx = offset + (upto ? width - 1 - i: i);
441							if (it.second.count(idx))
442								sig.append(it.second.at(idx));
443							else
444								sig.append(module->addWire(NEW_ID));
445						}
446	
447						cell->setPort(it.first, sig);
448					}
449	
450					lastcell = cell;
451					obj_attributes = &cell->attributes;
452					obj_parameters = &cell->parameters;
453					continue;
454				}
455	
456				obj_attributes = nullptr;
457				obj_parameters = nullptr;
458	
459				if (!strcmp(cmd, ".barbuf") || !strcmp(cmd, ".conn"))
460				{
461					char *p = strtok(NULL, " \t\r\n");
462					if (p == NULL)
463						goto error;
464	
465					char *q = strtok(NULL, " \t\r\n");
466					if (q == NULL)
467						goto error;
468	
469					module->connect(blif_wire(q), blif_wire(p));
470					continue;
471				}
472	
473				if (!strcmp(cmd, ".gateinit"))
474				{
475					char *p = strtok(NULL, " \t\r\n");
476					if (p == NULL)
477						goto error;
478	
479					char *n = strtok(p, "=");
480					char *init = strtok(NULL, "=");
481					if (n == NULL || init == NULL)
482						goto error;
483					if (init[0] != '0' && init[0] != '1')
484						goto error;
485	
486					if (blif_wire(n)->attributes.find(ID::init) == blif_wire(n)->attributes.end())
487						blif_wire(n)->attributes.emplace(ID::init, Const(init[0] == '1' ? 1 : 0, 1));
488					else
489						blif_wire(n)->attributes[ID::init] = Const(init[0] == '1' ? 1 : 0, 1);
490	
491					continue;
492				}
493	
494				if (!strcmp(cmd, ".names"))
495				{
496					char *p;
497					RTLIL::SigSpec input_sig, output_sig;
498					while ((p = strtok(NULL, " \t\r\n")) != NULL)
499						input_sig.append(blif_wire(p));
500					output_sig = input_sig.extract(input_sig.size()-1, 1);
501					input_sig = input_sig.extract(0, input_sig.size()-1);
502	
503					if (input_sig.size() == 0)
504					{
505						RTLIL::State state = RTLIL::State::Sa;
506						while (1) {
507							if (!read_next_line(buffer, buffer_size, line_count, f))
508								goto error;
509							for (int i = 0; buffer[i]; i++) {
510								if (buffer[i] == ' ' || buffer[i] == '\t')
511									continue;
512								if (i == 0 && buffer[i] == '.')
513									goto finished_parsing_constval;
514								if (buffer[i] == '0') {
515									if (state == RTLIL::State::S1)
516										goto error;
517									state = RTLIL::State::S0;
518									continue;
519								}
520								if (buffer[i] == '1') {
521									if (state == RTLIL::State::S0)
522										goto error;
523									state = RTLIL::State::S1;
524									continue;
525								}
526								goto error;
527							}
528						}
529	
530					finished_parsing_constval:
531						if (state == RTLIL::State::Sa)
532							state = RTLIL::State::S0;
533						if (output_sig.as_wire()->name == ID($undef))
534							state = RTLIL::State::Sx;
535						module->connect(RTLIL::SigSig(output_sig, state));
536						goto continue_without_read;
537					}
538	
539					if (sop_mode)
540					{
541						sopcell = module->addCell(NEW_ID, ID($sop));
542						sopcell->parameters[ID::WIDTH] = RTLIL::Const(input_sig.size());
543						sopcell->parameters[ID::DEPTH] = 0;
544						sopcell->parameters[ID::TABLE] = RTLIL::Const();
545						sopcell->setPort(ID::A, input_sig);
546						sopcell->setPort(ID::Y, output_sig);
547						sopmode = -1;
548						lastcell = sopcell;
549					}
550					else if (input_sig.size() > lut_input_plane_limit)
551					{
552						err_reason = stringf("names' input plane must have fewer than %d signals.", lut_input_plane_limit + 1);
553						goto error_with_reason;
554					}
555					else
556					{
557						RTLIL::Cell *cell = module->addCell(NEW_ID, ID($lut));
558						cell->parameters[ID::WIDTH] = RTLIL::Const(input_sig.size());
559						cell->parameters[ID::LUT] = RTLIL::Const(RTLIL::State::Sx, 1 << input_sig.size());
560						cell->setPort(ID::A, input_sig);
561						cell->setPort(ID::Y, output_sig);
562						lutptr = &cell->parameters.at(ID::LUT);
563						lut_default_state = RTLIL::State::Sx;
564						lastcell = cell;
565					}
566					continue;
567				}
568	
569				goto error;
570			}
571	
572			if (lutptr == NULL && sopcell == NULL)
573				goto error;
574	
575			char *input = strtok(buffer, " \t\r\n");
576			char *output = strtok(NULL, " \t\r\n");
577	
578			if (input == NULL || output == NULL || (strcmp(output, "0") && strcmp(output, "1")))
579				goto error;
580	
581			int input_len = strlen(input);
582	
583			if (sopcell)
584			{
585				log_assert(sopcell->parameters[ID::WIDTH].as_int() == input_len);
586				sopcell->parameters[ID::DEPTH] = sopcell->parameters[ID::DEPTH].as_int() + 1;
587	
588				Const::Builder table_bits_builder(input_len * 2);
589				for (int i = 0; i < input_len; i++)
590					switch (input[i]) {
591						case '0':
592							table_bits_builder.push_back(State::S1);
593							table_bits_builder.push_back(State::S0);
594							break;
595						case '1':
596							table_bits_builder.push_back(State::S0);
597							table_bits_builder.push_back(State::S1);
598							break;
599						default:
600							table_bits_builder.push_back(State::S0);
601							table_bits_builder.push_back(State::S0);
602							break;
603					}
604				sopcell->parameters[ID::TABLE].append(table_bits_builder.build());
605	
606				if (sopmode == -1) {
607					sopmode = (*output == '1');
608					if (!sopmode) {
609						SigSpec outnet = sopcell->getPort(ID::Y);
610						SigSpec tempnet = module->addWire(NEW_ID);
611						module->addNotGate(NEW_ID, tempnet, outnet);
612						sopcell->setPort(ID::Y, tempnet);
613					}
614				} else
615					log_assert(sopmode == (*output == '1'));
616			}
617	
618			if (lutptr)
619			{
620				if (input_len > lut_input_plane_limit)
621					goto error;
622	
623				for (int i = 0; i < (1 << input_len); i++) {
624					for (int j = 0; j < input_len; j++) {
625						char c1 = input[j];
626						if (c1 != '-') {
627							char c2 = (i & (1 << j)) != 0 ? '1' : '0';
628							if (c1 != c2)
629								goto try_next_value;
630						}
631					}
632					log_assert(i < lutptr->size());
633					lutptr->set(i, !strcmp(output, "0") ? RTLIL::State::S0 : RTLIL::State::S1);
634				try_next_value:;
635				}
636	
637				lut_default_state = !strcmp(output, "0") ? RTLIL::State::S1 : RTLIL::State::S0;
638			}
639		}
640	
641		return;
642	
643	error:
644		log_error("Syntax error in line %d!\n", line_count);
645	error_with_reason:
646		log_error("Syntax error in line %d: %s\n", line_count, err_reason);
647	}
648	
649	struct BlifFrontend : public Frontend {
650		BlifFrontend() : Frontend("blif", "read BLIF file") { }
651		void help() override
652		{
653			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
654			log("\n");
655			log("    read_blif [options] [filename]\n");
656			log("\n");
657			log("Load modules from a BLIF file into the current design.\n");
658			log("\n");
659			log("    -sop\n");
660			log("        Create $sop cells instead of $lut cells\n");
661			log("\n");
662			log("    -wideports\n");
663			log("        Merge ports that match the pattern 'name[int]' into a single\n");
664			log("        multi-bit port 'name'.\n");
665			log("\n");
666		}
667		void execute(std::istream *&f, std::string filename, std::vector<std::string> args, RTLIL::Design *design) override
668		{
669			bool sop_mode = false;
670			bool wideports = false;
671	
672			log_header(design, "Executing BLIF frontend.\n");
673	
674			size_t argidx;
675			for (argidx = 1; argidx < args.size(); argidx++) {
676				std::string arg = args[argidx];
677				if (arg == "-sop") {
678					sop_mode = true;
679					continue;
680				}
681				if (arg == "-wideports") {
682					wideports = true;
683					continue;
684				}
685				break;
686			}
687			extra_args(f, filename, args, argidx);
688	
689			parse_blif(design, *f, "", true, sop_mode, wideports);
690		}
691	} BlifFrontend;
692	
693	YOSYS_NAMESPACE_END
694

