32	
33	struct RTLILFrontendWorker {
34		std::istream *f = nullptr;
35		RTLIL::Design *design;
36		bool flag_nooverwrite = false;
37		bool flag_overwrite = false;
38		bool flag_lib = false;
39		bool flag_legalize = false;
40	
41		int line_num;
42		std::string line_buf;
43		// Substring of line_buf. Always newline-terminated, thus never empty.
44		std::string_view line;
45	
46		RTLIL::Module *current_module;
47		dict<RTLIL::IdString, RTLIL::Const> attrbuf;
48		std::vector<std::vector<RTLIL::SwitchRule*>*> switch_stack;
49		std::vector<RTLIL::CaseRule*> case_stack;
50	
51		template <typename... Args>
52		[[noreturn]]
53		void error(FmtString<TypeIdentity<Args>...> fmt, const Args &... args)
54		{
55			log_error("Parser error in line %d: %s\n", line_num, fmt.format(args...));
56		}
57	
58		template <typename... Args>
59		void warning(FmtString<TypeIdentity<Args>...> fmt, const Args &... args)
60		{
61			log_warning("In line %d: %s\n", line_num, fmt.format(args...));
62		}
63	
64		// May return an empty line if the stream is not good().
65		void advance_to_next_nonempty_line()
66		{
67			if (!f->good()) {
68				line = "\n";
69				return;
70			}
71			while (true) {
72				std::getline(*f, line_buf);
73				line_num++;
74				if (line_buf.empty() || line_buf[line_buf.size() - 1] != '\n')
75					line_buf += '\n';
76				line = line_buf;
77				consume_whitespace_and_comments();
78				if (line[0] != '\n' || !f->good())
79					break;
80			}
81		}
82	
83		void consume_whitespace_and_comments()
84		{
85			while (true) {
86				switch (line[0]) {
87				case ' ':
88				case '\t':
89					line = line.substr(1);
90					break;
91				case '#':
92					line = "\n";
93					return;
94				default:
95					return;
96				}
97			}
98		}
99	
100		bool try_parse_keyword(std::string_view keyword)
101		{
102			int keyword_size = keyword.size();
103			if (keyword != line.substr(0, keyword_size))
104				return false;
105			// This index is safe because `line` is always newline-terminated
106			// and `keyword` never contains a newline.
107			char ch = line[keyword_size];
108			if (ch >= 'a' && ch <= 'z')
109				return false;
110			line = line.substr(keyword_size);
111			consume_whitespace_and_comments();
112			return true;
113		}
114	
115		std::string error_token()
116		{
117			std::string result;
118			for (char ch : line) {
119				if (ch == '\n' || ch == ' ' || ch == '\t')
120					break;
121				result += ch;
122			}
123			return result;
124		}
125	
126		void expect_keyword(std::string_view keyword)
127		{
128			if (!try_parse_keyword(keyword))
129				error("Expected token `%s', got `%s'.", keyword, error_token());
130		}
131	
132		bool try_parse_char(char ch)
133		{
134			if (line[0] != ch)
135				return false;
136			line = line.substr(1);
137			consume_whitespace_and_comments();
138			return true;
139		}
140	
141		void expect_char(char ch)
142		{
143			if (!try_parse_char(ch))
144				error("Expected `%c', got `%s'.", ch, error_token());
145		}
146	
147		bool try_parse_eol()
148		{
149			if (line[0] != '\n')
150				return false;
151			advance_to_next_nonempty_line();
152			return true;
153		}
154	
155		void expect_eol()
156		{
157			if (!try_parse_eol())
158				error("Expected EOL, got `%s'.", error_token());
159		}
160	
161		std::optional<RTLIL::IdString> try_parse_id()
162		{
163			char ch = line[0];
164			if (ch != '\\' && ch != '$')
165				return std::nullopt;
166			int idx = 1;
167			while (true) {
168				ch = line[idx];
169				if (ch <= ' ' && (ch == ' ' || ch == '\t' || ch == '\n' || ch == '\r'))
170					break;
171				++idx;
172			}
173			IdString result(line.substr(0, idx));
174			line = line.substr(idx);
175			consume_whitespace_and_comments();
176			return result;
177		}
178	
179		RTLIL::IdString parse_id()
180		{
181			std::optional<RTLIL::IdString> id = try_parse_id();
182			if (!id.has_value())
183				error("Expected ID, got `%s'.", error_token());
184			return std::move(*id);
185		}
186	
187		long long parse_integer()
188		{
189			long long result = parse_integer_alone();
190			consume_whitespace_and_comments();
191			return result;
192		}
193	
194		long long parse_integer_alone()
195		{
196			int idx = 0;
197			if (line[idx] == '-')
198				++idx;
199			while (true) {
200				char ch = line[idx];
201				if (ch < '0' || ch > '9')
202					break;
203				++idx;
204			}
205			long long result;
206			if (std::from_chars(line.data(), line.data() + idx, result, 10).ec != std::errc{})
207				error("Invalid integer `%s'.", error_token());
208			line = line.substr(idx);
209			return result;
210		}
211	
212		std::string parse_string()
213		{
214			if (line[0] != '\"')
215				error("Expected string, got `%s'.", error_token());
216			std::string str;
217			int idx = 1;
218			while (true) {
219				int start_idx = idx;
220				char ch;
221				while (true) {
222					ch = line[idx];
223					if (ch == '"' || ch == '\n' || ch == '\\' || ch == 0)
224						break;
225					++idx;
226				}
227				str.append(line.data() + start_idx, line.data() + idx);
228				++idx;
229				if (ch == '"')
230					break;
231				if (ch == 0)
232					error("Null byte in string literal: `%s'.", line);
233				if (ch == '\n')
234					error("Unterminated string literal: `%s'.", line);
235				ch = line[idx++];
236				if (ch == 'n') {
237					ch = '\n';
238				} else if (ch == 't') {
239					ch = '\t';
240				} else if (ch >= '0' && ch <= '7') {
241					int v = ch - '0';
242					char next_ch = line[idx + 1];
243					if (next_ch >= '0' && next_ch <= '7') {
244						++idx;
245						v = v*8 + (next_ch - '0');
246						next_ch = line[idx + 1];
247						if (next_ch >= '0' && next_ch <= '7') {
248							++idx;
249							v = v*8 + (next_ch - '0');
250						}
251					}
252					ch = v;
253				}
254				str += ch;
255			}
256			line = line.substr(idx);
257			consume_whitespace_and_comments();
258			return str;
259		}
260	
261		RTLIL::Const parse_const()
262		{
263			if (line[0] == '"')
264				return RTLIL::Const(parse_string());
265	
266			bool negative_value = line[0] == '-';
267			long long width = parse_integer_alone();
268			// Can't test value<0 here because we need to stop parsing after '-0'
269			if (negative_value || line[0] != '\'') {
270				if (width < INT_MIN || width > INT_MAX)
271					error("Integer %lld out of range before `%s'.", width, error_token());
272				consume_whitespace_and_comments();
273				return RTLIL::Const(width);
274			}
275	
276			int idx = 1;
277			bool is_signed = line[1] == 's';
278			if (is_signed)
279				++idx;
280	
281			std::vector<RTLIL::State> bits;
282			if (width >= RTLIL::WIDTH_LIMIT)
283				error("Constant width %lld out of range before `%s`.", width, error_token());
284			bits.reserve(width);
285			int start_idx = idx;
286			while (true) {
287				RTLIL::State bit;
288				switch (line[idx]) {
289				case '0': bit = RTLIL::S0; break;
290				case '1': bit = RTLIL::S1; break;
291				case 'x': bit = RTLIL::Sx; break;
292				case 'z': bit = RTLIL::Sz; break;
293				case 'm': bit = RTLIL::Sm; break;
294				case '-': bit = RTLIL::Sa; break;
295				default: goto done;
296				}
297				bits.push_back(bit);
298				++idx;
299			}
300		done:
301			if (start_idx < idx)
302				std::reverse(bits.begin(), bits.end());
303	
304			if (GetSize(bits) > width)
305				bits.resize(width);
306			else if (GetSize(bits) < width) {
307				RTLIL::State extbit = RTLIL::Sx;
308				if (!bits.empty()) {
309					extbit = bits.back();
310					if (extbit == RTLIL::S1)
311						extbit = RTLIL::S0;
312				}
313				bits.resize(width, extbit);
314			}
315	
316			RTLIL::Const val(std::move(bits));
317			if (is_signed)
318				val.flags |= RTLIL::CONST_FLAG_SIGNED;
319			line = line.substr(idx);
320			consume_whitespace_and_comments();
321			return val;
322		}
323	
324		RTLIL::Wire *legalize_wire(RTLIL::IdString id)
325		{
326			int wires_size = current_module->wires_size();
327			if (wires_size == 0)
328				error("No wires found for legalization");
329			int hash = hash_ops<RTLIL::IdString>::hash(id).yield();
330			RTLIL::Wire *wire = current_module->wire_at(abs(hash % wires_size));
331			log("Legalizing wire `%s' to `%s'.\n", id.unescape(), wire->name.unescape());
332			return wire;
333		}
334	
335		RTLIL::SigSpec parse_sigspec()
336		{
337			RTLIL::SigSpec sig;
338	
339			if (try_parse_char('{')) {
340				std::vector<SigSpec> parts;
341				while (!try_parse_char('}'))
342					parts.push_back(parse_sigspec());
343				for (auto it = parts.rbegin(); it != parts.rend(); ++it)
344					sig.append(std::move(*it));
345			} else {
346				// We could add a special path for parsing IdStrings that must already exist,
347				// as here.
348				// We don't need to addref/release in this case.
349				std::optional<RTLIL::IdString> id = try_parse_id();
350				if (id.has_value()) {
351					RTLIL::Wire *wire = current_module->wire(*id);
352					if (wire == nullptr) {
353						if (flag_legalize)
354							wire = legalize_wire(*id);
355						else
356							error("Wire `%s' not found.", *id);
357					}
358					sig = RTLIL::SigSpec(wire);
359				} else {
360					sig = RTLIL::SigSpec(parse_const());
361				}
362			}
363	
364			while (try_parse_char('[')) {
365				int left = parse_integer();
366				if (left >= sig.size() || left < 0) {
367					if (flag_legalize) {
368						int legalized;
369						if (sig.size() == 0)
370							legalized = 0;
371						else
372							legalized = std::max(0, std::min(left, sig.size() - 1));
373						log("Legalizing bit index %d to %d.\n", left, legalized);
374						left = legalized;
375					} else {
376						error("bit index %d out of range", left);
377					}
378				}
379				if (try_parse_char(':')) {
380					int right = parse_integer();
381					if (right < 0) {
382						if (flag_legalize) {
383							log("Legalizing bit index %d to %d.\n", right, 0);
384							right = 0;
385						} else
386							error("bit index %d out of range", right);
387					}
388					if (left < right) {
389						if (flag_legalize) {
390							log("Legalizing bit index %d to %d.\n", left, right);
391							left = right;
392						} else
393							error("invalid slice [%d:%d]", left, right);
394					}
395					if (flag_legalize && left >= sig.size())
396						log("Legalizing slice %d:%d by igoring it\n", left, right);
397					else
398						sig = sig.extract(right, left - right + 1);
399				} else {
400					if (flag_legalize && left >= sig.size())
401						log("Legalizing slice %d by igoring it\n", left);
402					else
403						sig = sig.extract(left);
404				}
405				expect_char(']');
406			}
407	
408			return sig;
409		}
410	
411		void parse_module()
412		{
413			RTLIL::IdString module_name = parse_id();
414			expect_eol();
415	
416			bool delete_current_module = false;
417			if (design->has(module_name)) {
418				RTLIL::Module *existing_mod = design->module(module_name);
419				if (!flag_overwrite && (flag_lib || (attrbuf.count(ID::blackbox) && attrbuf.at(ID::blackbox).as_bool()))) {
420					log("Ignoring blackbox re-definition of module %s.\n", module_name);
421					delete_current_module = true;
422				} else if (!flag_nooverwrite && !flag_overwrite && !existing_mod->get_bool_attribute(ID::blackbox)) {
423					error("RTLIL error: redefinition of module %s.", module_name);
424				} else if (flag_nooverwrite) {
425					log("Ignoring re-definition of module %s.\n", module_name);
426					delete_current_module = true;
427				} else {
428					log("Replacing existing%s module %s.\n", existing_mod->get_bool_attribute(ID::blackbox) ? " blackbox" : "", module_name);
429					design->remove(existing_mod);
430				}
431			}
432	
433			current_module = new RTLIL::Module;
434			current_module->name = std::move(module_name);
435			current_module->attributes = std::move(attrbuf);
436			if (!delete_current_module)
437				design->add(current_module);
438	
439			while (true)
440			{
441				if (try_parse_keyword("attribute")) {
442					parse_attribute();
443					continue;
444				}
445				if (try_parse_keyword("parameter")) {
446					parse_parameter();
447					continue;
448				}
449				if (try_parse_keyword("connect")) {
450					parse_connect();
451					continue;
452				}
453				if (try_parse_keyword("wire")) {
454					parse_wire();
455					continue;
456				}
457				if (try_parse_keyword("cell")) {
458					parse_cell();
459					continue;
460				}
461				if (try_parse_keyword("memory")) {
462					parse_memory();
463					continue;
464				}
465				if (try_parse_keyword("process")) {
466					parse_process();
467					continue;
468				}
469				if (try_parse_keyword("end")) {
470					expect_eol();
471					break;
472				}
473				error("Unexpected token in module body: %s", error_token());
474			}
475	
476			if (attrbuf.size() != 0)
477				error("dangling attribute");
478			current_module->fixup_ports();
479			if (delete_current_module)
480				delete current_module;
481			else if (flag_lib)
482				current_module->makeblackbox();
483			current_module = nullptr;
484		}
485	
486		void parse_attribute()
487		{
488			RTLIL::IdString id = parse_id();
489			RTLIL::Const c = parse_const();
490			attrbuf.insert({std::move(id), std::move(c)});
491			expect_eol();
492		}
493	
494		void parse_parameter()
495		{
496			RTLIL::IdString id = parse_id();
497			current_module->avail_parameters(id);
498			if (try_parse_eol())
499				return;
500			RTLIL::Const c = parse_const();
501			current_module->parameter_default_values.insert({std::move(id), std::move(c)});
502			expect_eol();
503		}
504	
505		void parse_wire()
506		{
507			RTLIL::Wire *wire;
508			int width = 1;
509			int start_offset = 0;
510			int port_id = 0;
511			bool port_input = false;
512			bool port_output = false;
513			bool upto = false;
514			bool is_signed = false;
515	
516			while (true)
517			{
518				std::optional<RTLIL::IdString> id = try_parse_id();
519				if (id.has_value()) {
520					if (current_module->wire(*id) != nullptr) {
521					  if (flag_legalize) {
522							log("Legalizing redefinition of wire %s.\n", *id);
523							pool<RTLIL::Wire*> wires = {current_module->wire(*id)};
524							current_module->remove(wires);
525						} else
526							error("RTLIL error: redefinition of wire %s.", *id);
527					}
528					wire = current_module->addWire(std::move(*id));
529					break;
530				}
531				if (try_parse_keyword("width")){
532					long long width_val = parse_integer();
533					if (width_val < 0 || width_val >= RTLIL::WIDTH_LIMIT)
534						error("Wire width %lld out of range before `%s`.", width_val, error_token());
535					width = width_val;
536				}
537				else if (try_parse_keyword("upto"))
538					upto = true;
539				else if (try_parse_keyword("signed"))
540					is_signed = true;
541				else if (try_parse_keyword("offset")) {
542					long long offset_val = parse_integer();
543					if (offset_val < INT_MIN || offset_val > INT_MAX)
544						error("Wire offset %lld out of range before `%s`.", offset_val, error_token());
545					start_offset = offset_val;
546				}
547				else if (try_parse_keyword("input")) {
548					port_id = parse_integer();
549					port_input = true;
550				} else if (try_parse_keyword("output")) {
551					port_id = parse_integer();
552					port_output = true;
553				} else if (try_parse_keyword("inout")) {
554					port_id = parse_integer();
555					port_input = true;
556					port_output = true;
557				} else if (try_parse_eol())
558					error("Missing wire ID");
559				else
560					error("Unexpected wire option: %s", error_token());
561			}
562	
563			wire->attributes = std::move(attrbuf);
564			wire->width = width;
565			wire->upto = upto;
566			wire->start_offset = start_offset;
567			wire->is_signed = is_signed;
568			wire->port_id = port_id;
569			wire->port_input = port_input;
570			wire->port_output = port_output;
571			expect_eol();
572		}
573	
574		void parse_memory()
575		{
576			RTLIL::Memory *memory = new RTLIL::Memory;
577			memory->attributes = std::move(attrbuf);
578	
579			int width = 1;
580			int start_offset = 0;
581			int size = 0;
582			while (true)
583			{
584				std::optional<RTLIL::IdString> id = try_parse_id();
585				if (id.has_value()) {
586					if (current_module->memories.count(*id) != 0) {
587						if (flag_legalize) {
588							log("Legalizing redefinition of memory %s.\n", *id);
589							current_module->remove(current_module->memories.at(*id));
590						} else
591							error("RTLIL error: redefinition of memory %s.", *id);
592					}
593					memory->name = std::move(*id);
594					break;
595				}
596				if (try_parse_keyword("width")){
597					long long width_val = parse_integer();
598					if (width_val < 0 || width_val >= RTLIL::WIDTH_LIMIT)
599						error("Memory width %lld out of range before `%s`.", width_val, error_token());
600					width = width_val;
601				}
602				else if (try_parse_keyword("size")) {
603					long long size_val = parse_integer();
604					if (size_val < INT_MIN || size_val > INT_MAX)
605						error("Memory size %lld out of range before `%s`.", size_val, error_token());
606					size = size_val;
607				}
608				else if (try_parse_keyword("offset")) {
609					long long offset_val = parse_integer();
610					if (offset_val < INT_MIN || offset_val > INT_MAX)
611						error("Memory offset %lld out of range before `%s`.", offset_val, error_token());
612					start_offset = offset_val;
613				}
614				else if (try_parse_eol())
615					error("Missing memory ID");
616				else
617					error("Unexpected memory option: %s", error_token());
618			}
619			memory->width = width;
620			memory->start_offset = start_offset;
621			memory->size = size;
622			current_module->memories.insert({memory->name, memory});
623			expect_eol();
624		}
625	
626		void legalize_width_parameter(RTLIL::Cell *cell, RTLIL::IdString port_name)
627		{
628			std::string width_param_name = port_name.str() + "_WIDTH";
629			if (cell->parameters.count(width_param_name) == 0)
630				return;
631			RTLIL::Const &param = cell->parameters.at(width_param_name);
632			if (param.as_int() != 0)
633				return;
634			cell->parameters[width_param_name] = RTLIL::Const(cell->getPort(port_name).size());
635		}
636	
637		void parse_cell()
638		{
639			RTLIL::IdString cell_type = parse_id();
640			RTLIL::IdString cell_name = parse_id();
641			expect_eol();
642	
643			if (current_module->cell(cell_name) != nullptr) {
644				if (flag_legalize) {
645					RTLIL::IdString new_name;
646					int suffix = 1;
647					do {
648						new_name = RTLIL::IdString(cell_name.str() + "_" + std::to_string(suffix));
649						++suffix;
650					} while (current_module->cell(new_name) != nullptr);
651					log("Legalizing redefinition of cell %s by renaming to %s.\n", cell_name, new_name);
652					cell_name = new_name;
653				} else
654					error("RTLIL error: redefinition of cell %s.", cell_name);
655			}
656			RTLIL::Cell *cell = current_module->addCell(cell_name, cell_type);
657			cell->attributes = std::move(attrbuf);
658	
659			while (true)
660			{
661				if (try_parse_keyword("parameter")) {
662					bool is_signed = false;
663					bool is_real = false;
664					bool is_unsized = false;
665					if (try_parse_keyword("signed")) {
666						is_signed = true;
667					} else if (try_parse_keyword("real")) {
668						is_real = true;
669					} else if (try_parse_keyword("unsized")) {
670						is_unsized = true;
671					}
672					RTLIL::IdString param_name = parse_id();
673					RTLIL::Const val = parse_const();
674					if (is_signed)
675						val.flags |= RTLIL::CONST_FLAG_SIGNED;
676					if (is_real)
677						val.flags |= RTLIL::CONST_FLAG_REAL;
678					if (is_unsized)
679						val.flags |= RTLIL::CONST_FLAG_UNSIZED;
680					cell->parameters.insert({std::move(param_name), std::move(val)});
681					expect_eol();
682				} else if (try_parse_keyword("connect")) {
683					RTLIL::IdString port_name = parse_id();
684					if (cell->hasPort(port_name)) {
685						if (flag_legalize)
686							log("Legalizing redefinition of cell port %s.", port_name);
687						else
688							error("RTLIL error: redefinition of cell port %s.", port_name);
689					}
690					cell->setPort(std::move(port_name), parse_sigspec());
691					if (flag_legalize)
692						legalize_width_parameter(cell, port_name);
693					expect_eol();
694				} else if (try_parse_keyword("end")) {
695					expect_eol();
696					break;
697				} else {
698					error("Unexpected token in cell body: %s", error_token());
699				}
700			}
701		}
702	
703		void parse_connect()
704		{
705			if (attrbuf.size() != 0)
706				error("dangling attribute");
707			RTLIL::SigSpec s1 = parse_sigspec();
708			RTLIL::SigSpec s2 = parse_sigspec();
709			if (flag_legalize) {
710				int min_size = std::min(s1.size(), s2.size());
711				s1 = s1.extract(0, min_size);
712				s2 = s2.extract(0, min_size);
713			}
714			current_module->connect(std::move(s1), std::move(s2));
715			expect_eol();
716		}
717	
718		void parse_case_body(RTLIL::CaseRule *current_case)
719		{
720			while (true)
721			{
722				if (try_parse_keyword("attribute"))
723					parse_attribute();
724				else if (try_parse_keyword("switch"))
725					parse_switch();
726				else if (try_parse_keyword("assign")) {
727					if (attrbuf.size() != 0)
728						error("dangling attribute");
729					// See https://github.com/YosysHQ/yosys/pull/4765 for discussion on this
730					// warning
731					if (!switch_stack.back()->empty())
732						warning("case rule assign statements after switch statements may cause unexpected behaviour. "
733							"The assign statement is reordered to come before all switch statements.");
734					RTLIL::SigSpec s1 = parse_sigspec();
735					RTLIL::SigSpec s2 = parse_sigspec();
736					current_case->actions.push_back(RTLIL::SigSig(std::move(s1), std::move(s2)));
737					expect_eol();
738				} else
739					return;
740			}
741		}
742	
743		void parse_switch()
744		{
745			RTLIL::SwitchRule *rule = new RTLIL::SwitchRule;
746			rule->signal = parse_sigspec();
747			rule->attributes = std::move(attrbuf);
748			switch_stack.back()->push_back(rule);
749			expect_eol();
750	
751			while (true) {
752				if (try_parse_keyword("attribute")) {
753					parse_attribute();
754					continue;
755				}
756	
757				if (try_parse_keyword("end")) {
758					expect_eol();
759					break;
760				}
761	
762				expect_keyword("case");
763				RTLIL::CaseRule *case_rule = new RTLIL::CaseRule;
764				case_rule->attributes = std::move(attrbuf);
765				rule->cases.push_back(case_rule);
766				switch_stack.push_back(&case_rule->switches);
767				case_stack.push_back(case_rule);
768	
769				if (!try_parse_eol()) {
770					while (true) {
771						case_rule->compare.push_back(parse_sigspec());
772						if (try_parse_eol())
773							break;
774						expect_char(',');
775					}
776				}
777	
778				parse_case_body(case_rule);
779	
780				switch_stack.pop_back();
781				case_stack.pop_back();
782			}
783		}
784	
785		void parse_process()
786		{
787			RTLIL::IdString proc_name = parse_id();
788			expect_eol();
789	
790			if (current_module->processes.count(proc_name) != 0) {
791				if (flag_legalize) {
792					log("Legalizing redefinition of process %s.\n", proc_name);
793					current_module->remove(current_module->processes.at(proc_name));
794				} else
795					error("RTLIL error: redefinition of process %s.", proc_name);
796			}
797			RTLIL::Process *proc = current_module->addProcess(std::move(proc_name));
798			proc->attributes = std::move(attrbuf);
799	
800			switch_stack.clear();
801			switch_stack.push_back(&proc->root_case.switches);
802			case_stack.clear();
803			case_stack.push_back(&proc->root_case);
804	
805			parse_case_body(&proc->root_case);
806	
807			while (try_parse_keyword("sync"))
808			{
809				RTLIL::SyncRule *rule = new RTLIL::SyncRule;
810	
811				if (try_parse_keyword("low")) rule->type = RTLIL::ST0;
812				else if (try_parse_keyword("high")) rule->type = RTLIL::ST1;
813				else if (try_parse_keyword("posedge")) rule->type = RTLIL::STp;
814				else if (try_parse_keyword("negedge")) rule->type = RTLIL::STn;
815				else if (try_parse_keyword("edge")) rule->type = RTLIL::STe;
816				else if (try_parse_keyword("always")) rule->type = RTLIL::STa;
817				else if (try_parse_keyword("global")) rule->type = RTLIL::STg;
818				else if (try_parse_keyword("init")) rule->type = RTLIL::STi;
819				else error("Unexpected sync type: %s", error_token());
820	
821				if (rule->type != RTLIL::STa && rule->type != RTLIL::STg && rule->type != RTLIL::STi)
822					rule->signal = parse_sigspec();
823				proc->syncs.push_back(rule);
824				expect_eol();
825	
826				bool attributes_in_update_list = false;
827				while (true)
828				{
829					if (try_parse_keyword("update")) {
830						RTLIL::SigSpec s1 = parse_sigspec();
831						RTLIL::SigSpec s2 = parse_sigspec();
832						rule->actions.push_back(RTLIL::SigSig(std::move(s1), std::move(s2)));
833						expect_eol();
834						continue;
835					}
836	
837					if (try_parse_keyword("attribute")) {
838						attributes_in_update_list = true;
839						parse_attribute();
840						continue;
841					}
842	
843					if (!try_parse_keyword("memwr"))
844						break;
845	
846					RTLIL::MemWriteAction act;
847					act.attributes = std::move(attrbuf);
848					act.memid = parse_id();
849					act.address = parse_sigspec();
850					act.data = parse_sigspec();
851					act.enable = parse_sigspec();
852					act.priority_mask = parse_const();
853					rule->mem_write_actions.push_back(std::move(act));
854					expect_eol();
855				}
856				// The old parser allowed dangling attributes before a "sync" to carry through
857				// the "sync", so we will too, for now.
858				if (attributes_in_update_list && attrbuf.size() > 0)
859					error("dangling attribute");
860			}
861	
862			expect_keyword("end");
863			expect_eol();
864		}
865	
866		RTLILFrontendWorker(RTLIL::Design *design) : design(design) {}
867	
868		void parse(std::istream *f)
869		{
870			this->f = f;
871			line_num = 0;
872			advance_to_next_nonempty_line();
873			while (f->good())
874			{
875				if (try_parse_keyword("attribute")) {
876					parse_attribute();
877					continue;
878				}
879				if (try_parse_keyword("module")) {
880					parse_module();
881					continue;
882				}
883				if (try_parse_keyword("autoidx")) {
884					autoidx = std::max<int>(autoidx, parse_integer());
885					expect_eol();
886					continue;
887				}
888				error("Unexpected token: %s", error_token());
889			}
890			if (attrbuf.size() != 0)
891				error("dangling attribute");
892		}
893	};
894	
895	struct RTLILFrontend : public Frontend {
896		RTLILFrontend() : Frontend("rtlil", "read modules from RTLIL file") { }
897		void help() override
898		{
899			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
900			log("\n");
901			log("    read_rtlil [filename]\n");
902			log("\n");
903			log("Load modules from an RTLIL file to the current design. (RTLIL is a text\n");
904			log("representation of a design in yosys's internal format.)\n");
905			log("\n");
906			log("    -nooverwrite\n");
907			log("        ignore re-definitions of modules. (the default behavior is to\n");
908			log("        create an error message if the existing module is not a blackbox\n");
909			log("        module, and overwrite the existing module if it is a blackbox module.)\n");
910			log("\n");
911			log("    -overwrite\n");
912			log("        overwrite existing modules with the same name\n");
913			log("\n");
914			log("    -lib\n");
915			log("        only create empty blackbox modules\n");
916			log("\n");
917			log("    -legalize\n");
918			log("        prevent semantic errors (e.g. reference to unknown wire, redefinition of wire/cell)\n");
919			log("        by deterministically rewriting the input into something valid. Useful when using\n");
920			log("        fuzzing to generate random but valid RTLIL.\n");
921			log("\n");
922		}
923		void execute(std::istream *&f, std::string filename, std::vector<std::string> args, RTLIL::Design *design) override
924		{
925			RTLILFrontendWorker worker(design);
926	
927			log_header(design, "Executing RTLIL frontend.\n");
928	
929			size_t argidx;
930			for (argidx = 1; argidx < args.size(); argidx++) {
931				std::string arg = args[argidx];
932				if (arg == "-nooverwrite") {
933					worker.flag_nooverwrite = true;
934					worker.flag_overwrite = false;
935					continue;
936				}
937				if (arg == "-overwrite") {
938					worker.flag_nooverwrite = false;
939					worker.flag_overwrite = true;
940					continue;
941				}
942				if (arg == "-lib") {
943					worker.flag_lib = true;
944					continue;
945				}
946				if (arg == "-legalize") {
947					worker.flag_legalize = true;
948					continue;
949				}
950				break;
951			}
952			extra_args(f, filename, args, argidx);
953	
954			log("Input filename: %s\n", filename);
955	
956			worker.parse(f);
957		}
958	} RTLILFrontend;
959	
960	YOSYS_NAMESPACE_END
